        assert_eq!(cpu.read_byte(0x00213E), 0x31, "Data '1' at 0x213E");
        assert_eq!(cpu.read_byte(0x00213F), 0x30, "Data '0' at 0x213F");

        // Should have loaded a good chunk of bytes
        assert!(
            result.bytes_loaded > 300,
            "Should load >300 bytes, got {}",
            result.bytes_loaded
        );
    }
}

