        let mut buf = Vec::new();
        write(bytes, base_addr, entry, &mut buf).unwrap();
        String::from_utf8(buf).unwrap()
    }

    #[test]
    fn write_empty_no_entry() {
        assert_eq!(render(&[], 0, None), "");
    }

    #[test]
    fn write_empty_with_entry() {
        assert_eq!(render(&[], 0, Some(0x000093)), "G000093\n");
