enum InputSource {
    File(PathBuf),
    Stdin,
}

impl InputSource {
    fn label(&self) -> String {
        match self {
            InputSource::File(p) => p.display().to_string(),
            InputSource::Stdin => "<stdin>".to_string(),
        }
    }
}

#[derive(Debug)]
enum LgoSink {
